-- 0010_reformula_teens_young_web.sql
-- Reformula Roblox (TEENS) e Construct (YOUNG) com os cursos CourseFabric
-- ("Crie o seu Jogo: Obby!" e "Game Dev: seu Plataforma 2D") e cria o módulo
-- Web (YOUNG, "Crie a Web") a partir do course_web. Diagramas "onde clicar"
-- renderizados do próprio material em assets/. NÃO destrutivo e idempotente:
-- update in-place por ordem de position; Roblox aula 5 (Publicar) preservada.

do $mig$
declare
  v_mod uuid;
  v_ids uuid[];
  n int;
begin

  -- ===== ROBLOX: Crie o seu Jogo: Obby! =====
  select id into v_mod from public.modules where tool = 'roblox' order by position, created_at limit 1;
  if v_mod is not null then
    update public.modules
       set title = $mtroblox$Crie o seu Jogo: Obby!$mtroblox$, description = $mdroblox$Construa um obby (corrida de obstáculos) jogável, com checkpoints, lava e um final épico.$mdroblox$
     where id = v_mod;
    select array_agg(id order by position, created_at) into v_ids
      from public.lessons where module_id = v_mod;
    n := coalesce(array_length(v_ids, 1), 0);
    if n >= 1 then
      update public.lessons
         set title = $troblox1$Entrando no Roblox Studio$troblox1$, description = $droblox1$Conhecer a interface, inserir Parts, travar com Anchored, colorir e montar a plataforma inicial do obby.$droblox1$, body = $broblox1${"intro":"Conhecer a interface, inserir Parts, travar com Anchored, colorir e montar a plataforma inicial do obby.","material":[{"t":"h","x":"Tudo é uma 'Part'"},{"t":"p","x":"No Roblox, quase tudo que você vê é feito de Parts (peças). Você muda tamanho, cor, material e posição de cada uma. Um obby é só um monte de Parts bem colocadas!"},{"t":"h","x":"Ancore ou o mundo cai"},{"t":"p","x":"Toda peça tem uma propriedade Anchored (ancorada). Se estiver desligada, a peça cai com a gravidade quando você testar. Plataformas de obby precisam estar ANCORADAS."},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Abra um Baseplate"},{"t":"p","x":"No Studio, crie um New > Baseplate. Aquele chão cinza é a sua base para construir."},{"t":"img","url":"assets/roblox/onde_clicar_aula1.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"tip","x":"Ative Explorer e Properties na aba View — vamos usar o tempo todo."},{"t":"h","x":"Insira uma Part"},{"t":"p","x":"Na aba Home, clique em Part para inserir um bloco. Ele aparece no Explorer, dentro de Workspace."},{"t":"h","x":"Mova, gire e redimensione"},{"t":"p","x":"Use as ferramentas Move, Scale e Rotate (aba Home) para posicionar e esticar a peça como plataforma."},{"t":"h","x":"Ancore a peça"},{"t":"p","x":"Selecione a Part, vá em Properties e marque Anchored. Agora ela não cai quando você testar."},{"t":"tip","x":"Sem Anchored = plataforma despencando. Marque sempre!"},{"t":"h","x":"Dê cor e material"},{"t":"p","x":"Em Properties, mude Color e Material (tente Neon, Wood, Grass) para o obby ficar com a sua cara."},{"t":"h","x":"Monte a largada + 3 pulos"},{"t":"p","x":"Duplique a peça (Ctrl+D) e crie a plataforma inicial e os 3 primeiros pulos, com espaços entre elas."}],"resources":[{"label":"Roblox Studio (criar conta e baixar)","url":"https://create.roblox.com/","note":"Gratuito","kind":"link"},{"label":"Roblox — site oficial","url":"https://www.roblox.com/","note":"","kind":"link"}],"challenge":{"x":"A largada perfeita. Guarde: amanhã transformamos isso num percurso de verdade.","steps":["Crie uma plataforma de largada bem visível (cor diferente).","Faça 3 pulos com distâncias que dá para vencer sem cair sempre.","Teste (Play) e ajuste: nem fácil demais, nem impossível."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Studio","pt":"O programa onde criamos jogos…","phon":"STÚ-di-o","desc":"O programa onde criamos jogos do Roblox."},{"en":"Baseplate","pt":"O 'chão' cinza inicial do…","phon":"BÊIS-pleit","desc":"O 'chão' cinza inicial do projeto novo."},{"en":"Part","pt":"Uma peça","phon":"PART","desc":"Uma peça/bloco — o tijolo dos nossos jogos."},{"en":"Explorer","pt":"O painel que lista tudo que…","phon":"eks-PLÓ-rer","desc":"O painel que lista tudo que existe no jogo."},{"en":"Properties","pt":"Painel de propriedades","phon":"PRÓ-per-tis","desc":"Painel de propriedades (cor, tamanho...)."},{"en":"Anchor","pt":"Ancorar","phon":"ÊN-kor","desc":"Ancorar: travar a peça para ela não cair."}],"pairs":[["Studio","O programa onde criamos jogos…"],["Baseplate","O 'chão' cinza inicial do…"],["Part","Uma peça"],["Explorer","O painel que lista tudo que…"],["Properties","Painel de propriedades"],["Anchor","Ancorar"]]}}$broblox1$::jsonb
       where id = v_ids[1];
    end if;
    if n >= 2 then
      update public.lessons
         set title = $troblox2$Montando o percurso (o obby)$troblox2$, description = $droblox2$Construir o percurso completo de obstáculos e escrever o primeiro script: a lava que elimina o jogador.$droblox2$, body = $broblox2${"intro":"Construir o percurso completo de obstáculos e escrever o primeiro script: a lava que elimina o jogador.","material":[{"t":"h","x":"Programar é reagir a eventos"},{"t":"p","x":"Um script escuta EVENTOS. O evento Touched acontece quando algo encosta na peça. Aí o jogo executa uma ação — no nosso caso, tirar a vida do jogador. É a base de quase todo jogo!"},{"t":"h","x":"Coordenadas: X, Y, Z"},{"t":"p","x":"Toda peça tem uma posição em 3 números: X (esquerda/direita), Y (altura) e Z (frente/trás). Entender isso ajuda a alinhar plataformas com precisão."},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Estenda o percurso"},{"t":"p","x":"Continue a partir do Dia 1. Crie 6 ou mais obstáculos com dificuldade crescente: pulos, cantos, peças finas."},{"t":"img","url":"assets/roblox/onde_clicar_aula2.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"h","x":"Crie a peça de lava"},{"t":"p","x":"Insira uma Part, cor vermelha, material Neon, e ANCORE. Renomeie para 'Lava' no Explorer."},{"t":"h","x":"Adicione um Script na lava"},{"t":"p","x":"No Explorer, passe o mouse na Lava, clique no + e escolha Script. Uma janela de código abre."},{"t":"h","x":"Escreva o código da lava"},{"t":"p","x":"Digite o script do próximo slide. Ele detecta o toque e zera a vida do jogador (respawn)."},{"t":"h","x":"Teste a lava"},{"t":"p","x":"Play. Encoste na lava: você deve 'morrer' e voltar à largada. Se não, revise o script."},{"t":"tip","x":"Erros de código aparecem em vermelho na aba Output. Leia a linha indicada."},{"t":"h","x":"Código da aula"},{"t":"h","x":"O script da lava"},{"t":"code","lang":"Luau (Roblox)","lines":["-- coloque este Script DENTRO da peça de lava","local parte = script.Parent","","parte.Touched:Connect(function(outro)","  local h = outro.Parent:FindFirstChildWhichIsA(\"Humanoid\")","  if h then","    h.Health = 0   -- tira toda a vida = respawn","  end","end)"],"cap":"Touched é o evento; quando um Humanoid encosta, a vida vira 0 e o jogador renasce."}],"resources":[{"label":"Roblox Studio (criar conta e baixar)","url":"https://create.roblox.com/","note":"Gratuito","kind":"link"},{"label":"Roblox — site oficial","url":"https://www.roblox.com/","note":"","kind":"link"}],"challenge":{"x":"Um obstáculo assinatura. Amanhã: checkpoints para o jogador não recomeçar do zero!","steps":["Crie 1 obstáculo único e criativo (ponte fina, zigue-zague, salto duplo).","Coloque lava embaixo dele para aumentar a tensão.","Teste e garanta que é DIFÍCIL, mas possível."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Obby","pt":"Obstacle course","phon":"Ó-bi","desc":"Obstacle course: corrida de obstáculos."},{"en":"Platform","pt":"Plataforma","phon":"PLÁT-form","desc":"Plataforma."},{"en":"Lava","pt":"Lava","phon":"LÁ-va","desc":"Lava (a peça que 'mata' o jogador)."},{"en":"Script","pt":"Um conjunto de instruções","phon":"SCRIPT","desc":"Um conjunto de instruções (código) para o jogo."},{"en":"Touched","pt":"Evento 'foi tocado'","phon":"TÂTCHT","desc":"Evento 'foi tocado' — quando algo encosta na peça."},{"en":"Humanoid","pt":"A 'parte viva' do avatar","phon":"RIU-ma-noid","desc":"A 'parte viva' do avatar (tem vida/Health)."}],"pairs":[["Obby","Obstacle course"],["Platform","Plataforma"],["Lava","Lava"],["Script","Um conjunto de instruções"],["Touched","Evento 'foi tocado'"],["Humanoid","A 'parte viva' do avatar"]]}}$broblox2$::jsonb
       where id = v_ids[2];
    end if;
    if n >= 3 then
      update public.lessons
         set title = $troblox3$Checkpoints, vitória e decoração$troblox3$, description = $droblox3$Adicionar checkpoints com SpawnLocation, criar o bloco de vitória e decorar o mundo com segurança.$droblox3$, body = $broblox3${"intro":"Adicionar checkpoints com SpawnLocation, criar o bloco de vitória e decorar o mundo com segurança.","material":[{"t":"h","x":"Checkpoint = respawn mais justo"},{"t":"p","x":"Um SpawnLocation 'neutro' (Neutral = true) vira um checkpoint: quando o jogador toca nele, é ali que vai renascer. Assim, cair não significa recomeçar tudo — só voltar ao último checkpoint."},{"t":"h","x":"Cuidado com o Toolbox"},{"t":"p","x":"O Toolbox tem itens criados por outras pessoas. Alguns podem ter scripts ruins. Use só modelos simples, com o professor por perto, e nunca compartilhe senha ou dados pessoais no Roblox."},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Coloque o 1º SpawnLocation"},{"t":"p","x":"Insira um SpawnLocation na largada (Explorer > +). É onde o jogo começa."},{"t":"img","url":"assets/roblox/onde_clicar_aula3.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"h","x":"Crie checkpoints"},{"t":"p","x":"Insira mais SpawnLocations ao longo do percurso. Em cada um, marque Neutral = true em Properties."},{"t":"tip","x":"Neutral ligado = tocar nele vira o seu novo ponto de respawn."},{"t":"h","x":"Bloco de vitória"},{"t":"p","x":"No fim, crie uma Part dourada (Neon), ancore e renomeie para 'Win'. É o troféu do obby."},{"t":"h","x":"Decore o mundo"},{"t":"p","x":"Adicione cores, luzes (SpotLight) e 1 ou 2 itens simples do Toolbox — sempre com o professor revisando."},{"t":"h","x":"Publique o jogo"},{"t":"p","x":"File > Publish to Roblox As... Dê um nome e salve. Seu obby agora vive na nuvem!"},{"t":"h","x":"Código da aula"},{"t":"h","x":"(Opcional) Mensagem de vitória"},{"t":"code","lang":"Luau (Roblox)","lines":["-- Script DENTRO da peça 'Win'","local win = script.Parent","","win.Touched:Connect(function(outro)","  local h = outro.Parent:FindFirstChildWhichIsA(\"Humanoid\")","  if h then","    print(outro.Parent.Name .. \" venceu o obby!\")","  end","end)"],"cap":"Mesma ideia da lava, mas agora comemoramos: imprime o nome de quem venceu no Output."}],"resources":[{"label":"Roblox Studio (criar conta e baixar)","url":"https://create.roblox.com/","note":"Gratuito","kind":"link"},{"label":"Roblox — site oficial","url":"https://www.roblox.com/","note":"","kind":"link"}],"challenge":{"x":"Zona temática. Amanhã: testar de verdade, corrigir bugs e apresentar!","steps":["Escolha um tema (gelo, vulcão, espaço) e decore uma parte do obby com ele.","Garanta que há um checkpoint ANTES da parte mais difícil.","Publique e jogue do início para conferir os respawns."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Checkpoint","pt":"Ponto de salvamento no meio…","phon":"TCHÉK-point","desc":"Ponto de salvamento no meio do percurso."},{"en":"Spawn","pt":"Nascer","phon":"SPÓN","desc":"Nascer/aparecer — onde o jogador surge."},{"en":"Respawn","pt":"Renascer após 'morrer'","phon":"ri-SPÓN","desc":"Renascer após 'morrer'."},{"en":"Win","pt":"Vencer","phon":"UÍN","desc":"Vencer / vitória."},{"en":"Toolbox","pt":"Caixa de recursos com modelos…","phon":"TÚL-boks","desc":"Caixa de recursos com modelos prontos."},{"en":"Publish","pt":"Publicar o jogo na nuvem do…","phon":"PÁ-blish","desc":"Publicar o jogo na nuvem do Roblox."}],"pairs":[["Checkpoint","Ponto de salvamento no meio…"],["Spawn","Nascer"],["Respawn","Renascer após 'morrer'"],["Win","Vencer"],["Toolbox","Caixa de recursos com modelos…"],["Publish","Publicar o jogo na nuvem do…"]]}}$broblox3$::jsonb
       where id = v_ids[3];
    end if;
    if n >= 4 then
      update public.lessons
         set title = $troblox4$Testar, publicar e apresentar$troblox4$, description = $droblox4$Playtest completo, corrigir bugs, publicar a versão final e apresentar o obby jogando na TV.$droblox4$, body = $broblox4${"intro":"Playtest completo, corrigir bugs, publicar a versão final e apresentar o obby jogando na TV.","material":[{"t":"h","x":"O que é um 'bug'?"},{"t":"p","x":"Bug é qualquer coisa que não funciona como deveria: um pulo impossível, uma lava que não mata, um checkpoint que não salva. Testar (playtest) serve para caçar e consertar (fix) esses bugs."},{"t":"h","x":"Feedback é presente"},{"t":"p","x":"Quando um colega joga o seu obby e trava, isso é OURO: mostra exatamente o que melhorar. Ouça sem se ofender e anote. Depois, retribua testando o dele com carinho."},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Zere o próprio obby"},{"t":"p","x":"Jogue do início ao fim. Anote tudo que travar, for injusto ou não funcionar."},{"t":"img","url":"assets/roblox/onde_clicar_aula4.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"h","x":"Corrija os bugs"},{"t":"p","x":"Volte ao Studio e conserte: distâncias, Anchored, lava, checkpoints. Teste de novo."},{"t":"h","x":"Teste com um colega"},{"t":"p","x":"Troquem de cadeira e joguem o obby um do outro. Dê 2 elogios e 1 sugestão."},{"t":"h","x":"Capriche e publique"},{"t":"p","x":"Ajuste cores, dê um nome legal e faça o Publish final. Seu jogo está pronto para o mundo!"},{"t":"h","x":"Apresente jogando"},{"t":"p","x":"Mostre o obby na TV jogando ao vivo. Conte a parte mais difícil de criar."}],"resources":[{"label":"Roblox Studio (criar conta e baixar)","url":"https://create.roblox.com/","note":"Gratuito","kind":"link"},{"label":"Roblox — site oficial","url":"https://www.roblox.com/","note":"","kind":"link"}],"challenge":{"x":"Lançamento oficial. Parabéns, criador(a) de jogos! O mundo já pode jogar o seu obby.","steps":["Seu obby precisa ser 'zerável' do início ao fim.","Nome + cor de largada + bloco de vitória bem visíveis.","Publicado e apresentado ao vivo na TV."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Playtest","pt":"Testar o jogo jogando de…","phon":"PLÊI-test","desc":"Testar o jogo jogando de verdade."},{"en":"Bug","pt":"Um erro","phon":"BÂG","desc":"Um erro/defeito no jogo."},{"en":"Fix","pt":"Consertar","phon":"FÍKS","desc":"Consertar."},{"en":"Publish","pt":"Publicar a versão final","phon":"PÁ-blish","desc":"Publicar a versão final."},{"en":"Player","pt":"Jogador","phon":"PLÊI-er","desc":"Jogador."},{"en":"Feedback","pt":"Retorno","phon":"FÍD-bek","desc":"Retorno/opinião de quem jogou."}],"pairs":[["Playtest","Testar o jogo jogando de…"],["Bug","Um erro"],["Fix","Consertar"],["Publish","Publicar a versão final"],["Player","Jogador"],["Feedback","Retorno"]]}}$broblox4$::jsonb
       where id = v_ids[4];
    end if;
  end if;

  -- ===== CONSTRUCT: Game Dev: seu Plataforma 2D =====
  select id into v_mod from public.modules where tool = 'construct' order by position, created_at limit 1;
  if v_mod is not null then
    update public.modules
       set title = $mtconstruct$Game Dev: seu Plataforma 2D$mtconstruct$, description = $mdconstruct$Programe um jogo de plataforma completo — moedas, espinhos e a bandeira final — no navegador.$mdconstruct$
     where id = v_mod;
    select array_agg(id order by position, created_at) into v_ids
      from public.lessons where module_id = v_mod;
    n := coalesce(array_length(v_ids, 1), 0);
    if n >= 1 then
      update public.lessons
         set title = $tconstruct1$Conhecendo o Construct 3$tconstruct1$, description = $dconstruct1$Abrir o editor no navegador, entender Layout x Event Sheet, criar as 2 camadas e um personagem que já anda.$dconstruct1$, body = $bconstruct1${"intro":"Abrir o editor no navegador, entender Layout x Event Sheet, criar as 2 camadas e um personagem que já anda.","material":[{"t":"h","x":"Layout x Event Sheet"},{"t":"p","x":"O Layout é o PALCO (onde você posiciona os objetos). O Event Sheet é o ROTEIRO (a lógica: o que acontece e quando). Todo jogo no Construct é essa dupla: cena + eventos."},{"t":"h","x":"Behaviors: superpoderes prontos"},{"t":"p","x":"Um Behavior é um comportamento pré-programado. 'Platform' já dá gravidade, andar e pular ao personagem; 'Solid' faz o chão bloquear. Você ganha tempo e foca na parte criativa."},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Abra o editor"},{"t":"p","x":"No Chrome, acesse editor.construct.net e clique em New project. Não precisa instalar nada."},{"t":"img","url":"assets/construct/onde_clicar_aula1.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"tip","x":"Crie uma conta em construct.net para salvar seu projeto na nuvem."},{"t":"h","x":"Crie 2 camadas"},{"t":"p","x":"No painel Layers, deixe duas: 'Background' (fundo) e 'Game' (jogo). O plano Free permite 2 — perfeito."},{"t":"h","x":"Desenhe o Player"},{"t":"p","x":"Insira um Sprite na camada Game, desenhe/importe o personagem e renomeie o objeto para 'Player'."},{"t":"h","x":"Adicione o behavior Platform"},{"t":"p","x":"Com o Player selecionado, em Behaviors clique em Add e escolha Platform. Agora ele anda e pula."},{"t":"h","x":"Crie o chão sólido"},{"t":"p","x":"Insira um Tiled Background como chão, na camada Game, e adicione o behavior Solid para o Player pisar."},{"t":"h","x":"Dê Preview"},{"t":"p","x":"Clique em Preview (▶) e teste com as setas do teclado. O personagem deve andar e pular sobre o chão."},{"t":"tip","x":"O behavior Platform já usa Setas + Seta para cima (pulo) por padrão."}],"resources":[{"label":"Construct 3 — editor no navegador","url":"https://editor.construct.net/","note":"Roda direto no Chrome, versão gratuita","kind":"link"},{"label":"Construct — site oficial","url":"https://www.construct.net/","note":"","kind":"link"}],"challenge":{"x":"Um palco com estilo. Amanhã: plataformas, teclado e as primeiras MOEDAS com placar.","steps":["Deixe o Background com uma cor/fundo (céu) diferente do chão.","Ajuste o tamanho do Player e do chão para ficar agradável.","Garanta no Preview que ele anda e pula sem atravessar o chão."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Layout","pt":"A 'tela'","phon":"LÊI-aut","desc":"A 'tela'/fase do jogo (onde ficam os objetos)."},{"en":"Event Sheet","pt":"A folha de eventos","phon":"i-VÊNT XIT","desc":"A folha de eventos: onde fica a lógica do jogo."},{"en":"Sprite","pt":"Uma imagem","phon":"SPRÁIT","desc":"Uma imagem/objeto do jogo (personagem, moeda...)."},{"en":"Layer","pt":"Camada","phon":"LÊI-er","desc":"Camada (o plano Free permite 2)."},{"en":"Behavior","pt":"Comportamento pronto","phon":"bi-RÊI-vior","desc":"Comportamento pronto (ex.: Platform, Solid)."},{"en":"Preview","pt":"Rodar o jogo para testar","phon":"PRÍ-viu","desc":"Rodar o jogo para testar."}],"pairs":[["Layout","A 'tela'"],["Event Sheet","A folha de eventos"],["Sprite","Uma imagem"],["Layer","Camada"],["Behavior","Comportamento pronto"],["Preview","Rodar o jogo para testar"]]}}$bconstruct1$::jsonb
       where id = v_ids[1];
    end if;
    if n >= 2 then
      update public.lessons
         set title = $tconstruct2$Movimento, moedas e placar$tconstruct2$, description = $dconstruct2$Montar as plataformas, controlar pelo teclado e programar o primeiro evento: coletar moedas e somar pontos.$dconstruct2$, body = $bconstruct2${"intro":"Montar as plataformas, controlar pelo teclado e programar o primeiro evento: coletar moedas e somar pontos.","material":[{"t":"h","x":"Evento = condição → ação"},{"t":"p","x":"No Event Sheet, cada evento tem uma CONDIÇÃO (ex.: 'Player colidiu com Coin') e uma ou mais AÇÕES (ex.: 'destruir a moeda', 'somar 1 ponto'). É o 'SE isto, ENTÃO faça aquilo' de toda programação."},{"t":"h","x":"Variáveis guardam o estado"},{"t":"p","x":"Uma variável global 'Score' guarda quantas moedas você pegou. O jogo lê e atualiza esse número o tempo todo. Sem variáveis, o jogo não teria memória — nem placar, nem vidas, nem fases."},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Monte as plataformas"},{"t":"p","x":"Duplique o chão para criar plataformas em alturas diferentes. Todas com behavior Solid."},{"t":"img","url":"assets/construct/onde_clicar_aula2.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"h","x":"Adicione o Keyboard"},{"t":"p","x":"Insira o objeto Keyboard (uma vez no projeto). Ele permite que os eventos leiam as teclas."},{"t":"h","x":"Crie a variável Score"},{"t":"p","x":"No Event Sheet, crie uma Global variable chamada Score, tipo número, começando em 0."},{"t":"h","x":"Desenhe as moedas"},{"t":"p","x":"Crie um Sprite 'Coin' e espalhe várias cópias pela fase, em cima das plataformas."},{"t":"h","x":"Mostre o placar"},{"t":"p","x":"Insira um objeto Text 'PlacarTxt' na camada Game e posicione no canto da tela."},{"t":"h","x":"Programe coletar moeda"},{"t":"p","x":"No Event Sheet, adicione o evento do próximo slide: colidir com a moeda a destrói e soma 1 ponto."},{"t":"tip","x":"Add event → Player → On collision with Coin. Depois Add action."},{"t":"h","x":"Código da aula"},{"t":"h","x":"Evento: coletar moeda"},{"t":"code","lang":"Eventos (Construct 3)","lines":["-- Global variable:  Score = 0","","QUANDO  Player  ->  On collision with  Coin","FAÇA    Coin       ->  Destroy","        System     ->  Add 1 to Score","        PlacarTxt  ->  Set text: \"Moedas: \" & Score"],"cap":"Uma condição (colisão) e três ações. Assim funciona quase toda regra de jogo no Construct."}],"resources":[{"label":"Construct 3 — editor no navegador","url":"https://editor.construct.net/","note":"Roda direto no Chrome, versão gratuita","kind":"link"},{"label":"Construct — site oficial","url":"https://www.construct.net/","note":"","kind":"link"}],"challenge":{"x":"Circuito de moedas. Amanhã: como PERDER (espinhos) e como VENCER (a bandeira).","steps":["Posicione pelo menos 6 moedas exigindo pulos para pegar.","Garanta que o placar sobe certinho a cada moeda.","Equilibre: alcançável, mas que dê vontade de arriscar."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Solid","pt":"Comportamento que bloqueia","phon":"SÓ-lid","desc":"Comportamento que bloqueia (chão/parede)."},{"en":"Collision","pt":"Colisão","phon":"co-LÍ-jon","desc":"Colisão: quando dois objetos se encostam."},{"en":"Event","pt":"Evento = uma condição que…","phon":"i-VÊNT","desc":"Evento = uma condição que dispara ações."},{"en":"Action","pt":"Ação executada quando a…","phon":"ÁK-shon","desc":"Ação executada quando a condição é verdadeira."},{"en":"Variable","pt":"Variável","phon":"VÉ-ri-a-bol","desc":"Variável: uma 'caixinha' que guarda um valor (ex.: Score)."},{"en":"Keyboard","pt":"Teclado","phon":"KÍ-bord","desc":"Teclado (objeto que lê as teclas)."}],"pairs":[["Solid","Comportamento que bloqueia"],["Collision","Colisão"],["Event","Evento = uma condição que…"],["Action","Ação executada quando a…"],["Variable","Variável"],["Keyboard","Teclado"]]}}$bconstruct2$::jsonb
       where id = v_ids[2];
    end if;
    if n >= 3 then
      update public.lessons
         set title = $tconstruct3$As regras: perder e vencer$tconstruct3$, description = $dconstruct3$Adicionar o obstáculo que reinicia a fase (perder) e a bandeira de vitória (vencer) — o jogo fica completo.$dconstruct3$, body = $bconstruct3${"intro":"Adicionar o obstáculo que reinicia a fase (perder) e a bandeira de vitória (vencer) — o jogo fica completo.","material":[{"t":"h","x":"O loop do jogo"},{"t":"p","x":"Todo jogo tem um ciclo: um estado inicial, uma jogabilidade, e condições de FIM (vitória ou derrota) que reiniciam o ciclo. Hoje você fecha esse loop: dá um jeito de perder e um de vencer."},{"t":"h","x":"Otimização: menos é mais"},{"t":"p","x":"O plano Free limita a 50 eventos. Isso não é problema — é treino de dev! Reaproveite eventos, use variáveis e evite repetição. Jogos incríveis já foram feitos com pouquíssimos eventos."},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Crie o espinho (Spike)"},{"t":"p","x":"Desenhe um Sprite 'Spike' e coloque em pontos perigosos da fase, entre plataformas."},{"t":"img","url":"assets/construct/onde_clicar_aula3.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"h","x":"Programe a derrota"},{"t":"p","x":"Evento: Player colide com Spike → System: Restart layout. Encostar no espinho reinicia a fase."},{"t":"h","x":"Crie a bandeira (Goal)"},{"t":"p","x":"Desenhe um Sprite 'Goal' no fim do percurso — o objetivo a alcançar."},{"t":"h","x":"Crie o layout de Vitória"},{"t":"p","x":"Adicione um novo Layout 'Vitoria' com um Text grande: 'VOCÊ VENCEU!' e o placar."},{"t":"h","x":"Programe a vitória"},{"t":"p","x":"Evento: Player colide com Goal → System: Go to layout 'Vitoria'. Fim feliz!"},{"t":"tip","x":"Veja o contador de eventos: dá para fazer tudo isso com poucos!"},{"t":"h","x":"Código da aula"},{"t":"h","x":"Eventos: perder e vencer"},{"t":"code","lang":"Eventos (Construct 3)","lines":["QUANDO  Player  ->  On collision with  Spike","FAÇA    System  ->  Restart layout          -- perdeu","","QUANDO  Player  ->  On collision with  Goal","FAÇA    System  ->  Go to layout \"Vitoria\"   -- venceu"],"cap":"Duas regras fecham o loop do jogo: uma para perder, outra para vencer."}],"resources":[{"label":"Construct 3 — editor no navegador","url":"https://editor.construct.net/","note":"Roda direto no Chrome, versão gratuita","kind":"link"},{"label":"Construct — site oficial","url":"https://www.construct.net/","note":"","kind":"link"}],"challenge":{"x":"Dificuldade justa. Amanhã: polir, checar os limites do plano Free e apresentar!","steps":["Coloque espinhos que exijam cuidado, mas nunca 'impossíveis'.","Garanta um caminho claro até a bandeira (Goal).","Teste perder e vencer pelo menos 1 vez cada."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Variable","pt":"Variável","phon":"VÉ-ri-a-bol","desc":"Variável (valor guardado, ex.: Score)."},{"en":"Restart","pt":"Reiniciar a fase","phon":"ri-STÁRT","desc":"Reiniciar a fase."},{"en":"Win","pt":"Vencer","phon":"UÍN","desc":"Vencer."},{"en":"Lose","pt":"Perder","phon":"LÚZ","desc":"Perder."},{"en":"Layout","pt":"Cena","phon":"LÊI-aut","desc":"Cena/fase (usaremos uma de vitória)."},{"en":"Text","pt":"Objeto de texto na tela","phon":"TÉKST","desc":"Objeto de texto na tela."}],"pairs":[["Variable","Variável"],["Restart","Reiniciar a fase"],["Win","Vencer"],["Lose","Perder"],["Layout","Cena"],["Text","Objeto de texto na tela"]]}}$bconstruct3$::jsonb
       where id = v_ids[3];
    end if;
    if n >= 4 then
      update public.lessons
         set title = $tconstruct4$Polir, testar e apresentar$tconstruct4$, description = $dconstruct4$Ajustes finais dentro dos limites do plano Free, caça a bugs, tela de instruções e apresentação no Preview.$dconstruct4$, body = $bconstruct4${"intro":"Ajustes finais dentro dos limites do plano Free, caça a bugs, tela de instruções e apresentação no Preview.","material":[{"t":"h","x":"Debugar é ler o próprio jogo"},{"t":"p","x":"Debugar é investigar por que algo não funciona: um evento na ordem errada, um objeto sem nome, uma variável não atualizada. O painel de eventos é o seu mapa — leia de cima para baixo."},{"t":"h","x":"Apresente como um dev"},{"t":"p","x":"Ao mostrar seu jogo, explique UMA regra que você programou (condição → ação) e uma decisão de otimização. Isso mostra que você entende o que construiu, não só que 'funcionou'."},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Playtest completo"},{"t":"p","x":"Jogue do início ao fim várias vezes. Anote todo bug: pulo, colisão, placar, vitória."},{"t":"img","url":"assets/construct/onde_clicar_aula4.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"h","x":"Corrija os bugs"},{"t":"p","x":"Volte ao Event Sheet e conserte. Teste no Preview a cada correção."},{"t":"h","x":"Tela de instruções"},{"t":"p","x":"Adicione um Text de início explicando os controles e o objetivo (pegar moedas, evitar espinhos)."},{"t":"h","x":"Polir dentro dos limites"},{"t":"p","x":"Ajuste cores, posições e (opcional) um som. Confira: 2 camadas e menos de 50 eventos."},{"t":"h","x":"Apresente no Preview"},{"t":"p","x":"Rode o jogo na TV. Mostre andar, coletar, perder e vencer. Explique 1 evento que você criou."}],"resources":[{"label":"Construct 3 — editor no navegador","url":"https://editor.construct.net/","note":"Roda direto no Chrome, versão gratuita","kind":"link"},{"label":"Construct — site oficial","url":"https://www.construct.net/","note":"","kind":"link"}],"challenge":{"x":"Build jogável. Parabéns, game dev! Você programou um jogo completo respeitando limites reais.","steps":["O jogo precisa começar, jogar, PERDER e VENCER sem travar.","Instruções na tela + placar funcionando.","Dentro do plano Free (2 camadas, < 50 eventos) e apresentado no Preview."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Debug","pt":"Encontrar e corrigir erros","phon":"di-BÂG","desc":"Encontrar e corrigir erros."},{"en":"Playtest","pt":"Testar jogando de verdade","phon":"PLÊI-test","desc":"Testar jogando de verdade."},{"en":"Preview","pt":"Rodar o jogo","phon":"PRÍ-viu","desc":"Rodar o jogo (como apresentamos)."},{"en":"Bug","pt":"Erro","phon":"BÂG","desc":"Erro/defeito no jogo."},{"en":"Polish","pt":"Polir","phon":"PÓ-lish","desc":"Polir: dar acabamento e capricho."},{"en":"Feedback","pt":"Opinião de quem jogou","phon":"FÍD-bek","desc":"Opinião de quem jogou."}],"pairs":[["Debug","Encontrar e corrigir erros"],["Playtest","Testar jogando de verdade"],["Preview","Rodar o jogo"],["Bug","Erro"],["Polish","Polir"],["Feedback","Opinião de quem jogou"]]}}$bconstruct4$::jsonb
       where id = v_ids[4];
    end if;
