  -- ===== WEB (novo módulo YOUNG): Crie a Web: sua Página Interativa =====
  select id into v_mod from public.modules where title = $mtweb$Crie a Web: sua Página Interativa$mtweb$ limit 1;
  if v_mod is null then
    insert into public.modules (title, description, tool, position, is_published, stage)
      values ($mtweb$Crie a Web: sua Página Interativa$mtweb$, $mdweb$Programe do zero uma página com HTML, CSS e JavaScript — incluindo um mini-jogo que funciona de verdade.$mdweb$, null, 7, true, 'young')
      returning id into v_mod;
  else
    update public.modules set description = $mdweb$Programe do zero uma página com HTML, CSS e JavaScript — incluindo um mini-jogo que funciona de verdade.$mdweb$, stage = 'young' where id = v_mod;
  end if;
  select array_agg(id order by position, created_at) into v_ids
    from public.lessons where module_id = v_mod;
  n := coalesce(array_length(v_ids, 1), 0);
  if n >= 1 then
    update public.lessons
       set title = $tweb1$HTML: a estrutura da página$tweb1$, description = $dweb1$Montar a estrutura da página em HTML: o esqueleto do documento, títulos, textos, imagem, link e um botão.$dweb1$, body = $bweb1${"intro":"Montar a estrutura da página em HTML: o esqueleto do documento, títulos, textos, imagem, link e um botão.","material":[{"t":"h","x":"O que é HTML?"},{"t":"p","x":"HTML é a linguagem que descreve a ESTRUTURA da página: o que é título, o que é parágrafo, o que é imagem. O navegador lê esse texto e desenha a página. Sem HTML, não há página."},{"t":"h","x":"Tags vêm em pares"},{"t":"p","x":"Quase toda tag abre e fecha: <p>texto</p>. O que fica entre elas é o conteúdo. Esquecer de fechar uma tag é o erro nº 1 de quem começa — cuidado com isso!"},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Abra o editor e crie o arquivo"},{"t":"p","x":"No VS Code (ou Bloco de Notas), crie um arquivo chamado index.html numa pasta sua."},{"t":"img","url":"assets/web/onde_clicar_aula1.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"tip","x":"O nome index.html é especial: é a página inicial de qualquer site."},{"t":"h","x":"Escreva o esqueleto"},{"t":"p","x":"Digite a estrutura básica do próximo slide: DOCTYPE, html, head e body. É a base de toda página."},{"t":"h","x":"Abra no navegador"},{"t":"p","x":"Salve (Ctrl+S) e dê duplo clique no arquivo para abrir no navegador. Você verá seu título aparecer."},{"t":"h","x":"Adicione conteúdo"},{"t":"p","x":"Dentro do body, coloque um <h1>, um <p>, uma <img>, um <a> (link) e um <button> (2º slide de código)."},{"t":"h","x":"Salve e atualize"},{"t":"p","x":"A cada mudança: Ctrl+S no editor e F5 no navegador. Assim você vê a página evoluindo."},{"t":"tip","x":"Sempre que 'nada mudou', você provavelmente esqueceu de salvar ou de atualizar."},{"t":"h","x":"Código da aula"},{"t":"h","x":"O esqueleto HTML"},{"t":"code","lang":"HTML","lines":["<!DOCTYPE html>","<html lang=\"pt-br\">","<head>","  <meta charset=\"utf-8\">","  <title>Minha Página</title>","</head>","<body>","  <h1>Oi! Eu sou o(a) [seu nome]</h1>","</body>","</html>"],"cap":"Salve como index.html e abra no navegador. Todo documento HTML tem head (dados) e body (conteúdo)."},{"t":"h","x":"Conteúdo da página"},{"t":"code","lang":"HTML","lines":["<h1>Meu Perfil</h1>","<img src=\"foto.png\" alt=\"minha foto\" width=\"150\">","<p>Eu gosto de games e tecnologia.</p>","<a href=\"https://exemplo.com\">Meu link</a>","<button id=\"btnJogar\">Jogar!</button>"],"cap":"Título, imagem, texto, link e um botão. O id do botão será usado pelo JavaScript no Dia 3."}],"resources":[{"label":"VS Code para Web (editor no navegador)","url":"https://vscode.dev/","note":"Gratuito, sem instalar","kind":"link"},{"label":"MDN Web Docs em português","url":"https://developer.mozilla.org/pt-BR/","note":"Documentação oficial de HTML/CSS/JS","kind":"link"}],"challenge":{"x":"Sua página, sua cara. Amanhã: deixar tudo bonito com CSS.","steps":["Troque os textos pelos seus (nome, o que você gosta).","Adicione uma lista (<ul><li>) com 3 hobbies.","Garanta que TODAS as tags estão fechadas corretamente."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Tag","pt":"Marcação como <p>. Quase…","phon":"TÉG","desc":"Marcação como <p>. Quase sempre abre e fecha: <p></p>."},{"en":"Element","pt":"Uma tag + seu conteúdo","phon":"É-le-ment","desc":"Uma tag + seu conteúdo (o 'bloco' completo)."},{"en":"Attribute","pt":"Info extra dentro da tag","phon":"Á-tri-biut","desc":"Info extra dentro da tag (ex.: src, href)."},{"en":"Head","pt":"Cabeçalho do documento","phon":"RÉD","desc":"Cabeçalho do documento (dados invisíveis)."},{"en":"Body","pt":"Corpo","phon":"BÓ-di","desc":"Corpo: o conteúdo que aparece na tela."},{"en":"Heading","pt":"Título","phon":"RÉ-ding","desc":"Título (<h1> é o maior)."}],"pairs":[["Tag","Marcação como <p>. Quase…"],["Element","Uma tag + seu conteúdo"],["Attribute","Info extra dentro da tag"],["Head","Cabeçalho do documento"],["Body","Corpo"],["Heading","Título"]]}}$bweb1$::jsonb
     where id = v_ids[1];
  else
    insert into public.lessons (module_id, title, description, tool, position, reward_coins, is_published, body)
      values (v_mod, $tweb1$HTML: a estrutura da página$tweb1$, $dweb1$Montar a estrutura da página em HTML: o esqueleto do documento, títulos, textos, imagem, link e um botão.$dweb1$, null, 1, 20, true, $bweb1${"intro":"Montar a estrutura da página em HTML: o esqueleto do documento, títulos, textos, imagem, link e um botão.","material":[{"t":"h","x":"O que é HTML?"},{"t":"p","x":"HTML é a linguagem que descreve a ESTRUTURA da página: o que é título, o que é parágrafo, o que é imagem. O navegador lê esse texto e desenha a página. Sem HTML, não há página."},{"t":"h","x":"Tags vêm em pares"},{"t":"p","x":"Quase toda tag abre e fecha: <p>texto</p>. O que fica entre elas é o conteúdo. Esquecer de fechar uma tag é o erro nº 1 de quem começa — cuidado com isso!"},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Abra o editor e crie o arquivo"},{"t":"p","x":"No VS Code (ou Bloco de Notas), crie um arquivo chamado index.html numa pasta sua."},{"t":"img","url":"assets/web/onde_clicar_aula1.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"tip","x":"O nome index.html é especial: é a página inicial de qualquer site."},{"t":"h","x":"Escreva o esqueleto"},{"t":"p","x":"Digite a estrutura básica do próximo slide: DOCTYPE, html, head e body. É a base de toda página."},{"t":"h","x":"Abra no navegador"},{"t":"p","x":"Salve (Ctrl+S) e dê duplo clique no arquivo para abrir no navegador. Você verá seu título aparecer."},{"t":"h","x":"Adicione conteúdo"},{"t":"p","x":"Dentro do body, coloque um <h1>, um <p>, uma <img>, um <a> (link) e um <button> (2º slide de código)."},{"t":"h","x":"Salve e atualize"},{"t":"p","x":"A cada mudança: Ctrl+S no editor e F5 no navegador. Assim você vê a página evoluindo."},{"t":"tip","x":"Sempre que 'nada mudou', você provavelmente esqueceu de salvar ou de atualizar."},{"t":"h","x":"Código da aula"},{"t":"h","x":"O esqueleto HTML"},{"t":"code","lang":"HTML","lines":["<!DOCTYPE html>","<html lang=\"pt-br\">","<head>","  <meta charset=\"utf-8\">","  <title>Minha Página</title>","</head>","<body>","  <h1>Oi! Eu sou o(a) [seu nome]</h1>","</body>","</html>"],"cap":"Salve como index.html e abra no navegador. Todo documento HTML tem head (dados) e body (conteúdo)."},{"t":"h","x":"Conteúdo da página"},{"t":"code","lang":"HTML","lines":["<h1>Meu Perfil</h1>","<img src=\"foto.png\" alt=\"minha foto\" width=\"150\">","<p>Eu gosto de games e tecnologia.</p>","<a href=\"https://exemplo.com\">Meu link</a>","<button id=\"btnJogar\">Jogar!</button>"],"cap":"Título, imagem, texto, link e um botão. O id do botão será usado pelo JavaScript no Dia 3."}],"resources":[{"label":"VS Code para Web (editor no navegador)","url":"https://vscode.dev/","note":"Gratuito, sem instalar","kind":"link"},{"label":"MDN Web Docs em português","url":"https://developer.mozilla.org/pt-BR/","note":"Documentação oficial de HTML/CSS/JS","kind":"link"}],"challenge":{"x":"Sua página, sua cara. Amanhã: deixar tudo bonito com CSS.","steps":["Troque os textos pelos seus (nome, o que você gosta).","Adicione uma lista (<ul><li>) com 3 hobbies.","Garanta que TODAS as tags estão fechadas corretamente."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Tag","pt":"Marcação como <p>. Quase…","phon":"TÉG","desc":"Marcação como <p>. Quase sempre abre e fecha: <p></p>."},{"en":"Element","pt":"Uma tag + seu conteúdo","phon":"É-le-ment","desc":"Uma tag + seu conteúdo (o 'bloco' completo)."},{"en":"Attribute","pt":"Info extra dentro da tag","phon":"Á-tri-biut","desc":"Info extra dentro da tag (ex.: src, href)."},{"en":"Head","pt":"Cabeçalho do documento","phon":"RÉD","desc":"Cabeçalho do documento (dados invisíveis)."},{"en":"Body","pt":"Corpo","phon":"BÓ-di","desc":"Corpo: o conteúdo que aparece na tela."},{"en":"Heading","pt":"Título","phon":"RÉ-ding","desc":"Título (<h1> é o maior)."}],"pairs":[["Tag","Marcação como <p>. Quase…"],["Element","Uma tag + seu conteúdo"],["Attribute","Info extra dentro da tag"],["Head","Cabeçalho do documento"],["Body","Corpo"],["Heading","Título"]]}}$bweb1$::jsonb);
  end if;
  if n >= 2 then
    update public.lessons
       set title = $tweb2$CSS: o design da página$tweb2$, description = $dweb2$Estilizar a página com CSS: cores, fontes, o box model e um layout centralizado com flexbox.$dweb2$, body = $bweb2${"intro":"Estilizar a página com CSS: cores, fontes, o box model e um layout centralizado com flexbox.","material":[{"t":"h","x":"HTML estrutura, CSS embeleza"},{"t":"p","x":"O HTML diz O QUE é cada coisa; o CSS diz COMO cada coisa aparece: cor, tamanho, fonte, posição. Separar conteúdo de estilo é uma das ideias mais importantes da web."},{"t":"h","x":"O box model"},{"t":"p","x":"Todo elemento é uma caixa com: conteúdo, padding (espaço interno), border (borda) e margin (espaço externo). Entender a 'caixa' é o segredo para controlar qualquer layout."},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Adicione o <style>"},{"t":"p","x":"No <head>, crie uma tag <style></style>. É onde o CSS vai morar (jeito mais simples para começar)."},{"t":"img","url":"assets/web/onde_clicar_aula2.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"h","x":"Estilize o body"},{"t":"p","x":"Escolha fonte, cor de fundo e cor do texto para a página inteira (1º slide de código)."},{"t":"h","x":"Deixe o botão bonito"},{"t":"p","x":"Dê cor, padding e cantos arredondados (border-radius) ao <button>. Ele vira um botão de verdade."},{"t":"h","x":"Centralize com flexbox"},{"t":"p","x":"Crie uma .classe com display:flex para alinhar e centralizar os elementos (2º slide de código)."},{"t":"h","x":"Refine"},{"t":"p","x":"Ajuste tamanhos, espaços (margin/padding) e cores até a página ficar do seu jeito."},{"t":"tip","x":"Mude 1 propriedade por vez e atualize (F5) para ver o efeito."},{"t":"h","x":"Código da aula"},{"t":"h","x":"Estilo base (body e button)"},{"t":"code","lang":"CSS","lines":["body {","  font-family: sans-serif;","  background: #0f172a;","  color: #f8fafc;","  text-align: center;","}","button {","  background: #0ea5a9;","  color: #ffffff;","  padding: 12px 22px;","  border: none;","  border-radius: 10px;","}"],"cap":"Cada regra é seletor { propriedade: valor; }. Aqui o body e o button ganham cor, fonte e cantos."},{"t":"h","x":"Layout com flexbox"},{"t":"code","lang":"CSS","lines":[".container {","  display: flex;","  gap: 16px;","  justify-content: center;","  align-items: center;","}"],"cap":"Coloque os botões dentro de uma <div class=\"container\"> para alinhá-los lado a lado, centralizados."}],"resources":[{"label":"VS Code para Web (editor no navegador)","url":"https://vscode.dev/","note":"Gratuito, sem instalar","kind":"link"},{"label":"MDN Web Docs em português","url":"https://developer.mozilla.org/pt-BR/","note":"Documentação oficial de HTML/CSS/JS","kind":"link"}],"challenge":{"x":"Identidade visual. Amanhã: dar VIDA à página com JavaScript e criar o mini-jogo!","steps":["Defina uma paleta de 2 ou 3 cores e use-a de forma consistente.","Deixe o botão com um efeito de hover (button:hover { ... }).","Garanta bom espaçamento (nada 'grudado')."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Selector","pt":"O que o CSS mira","phon":"se-LÉK-tor","desc":"O que o CSS mira (ex.: body, button, .classe)."},{"en":"Class","pt":"Um 'apelido'","phon":"CLÁS","desc":"Um 'apelido' (.container) para estilizar vários elementos."},{"en":"Property","pt":"O que muda","phon":"PRÓ-per-ti","desc":"O que muda (color, font-size, margin...)."},{"en":"Color","pt":"Cor","phon":"CÂ-lor","desc":"Cor (ex.: #0EA5A9)."},{"en":"Margin","pt":"Espaço POR FORA do elemento","phon":"MÁR-jin","desc":"Espaço POR FORA do elemento."},{"en":"Flexbox","pt":"Sistema para alinhar…","phon":"FLÉKS-boks","desc":"Sistema para alinhar elementos em linha/coluna."}],"pairs":[["Selector","O que o CSS mira"],["Class","Um 'apelido'"],["Property","O que muda"],["Color","Cor"],["Margin","Espaço POR FORA do elemento"],["Flexbox","Sistema para alinhar…"]]}}$bweb2$::jsonb
