","  border-radius: 10px;","}"],"cap":"Cada regra é seletor { propriedade: valor; }. Aqui o body e o button ganham cor, fonte e cantos."},{"t":"h","x":"Layout com flexbox"},{"t":"code","lang":"CSS","lines":[".container {","  display: flex;","  gap: 16px;","  justify-content: center;","  align-items: center;","}"],"cap":"Coloque os botões dentro de uma <div class=\"container\"> para alinhá-los lado a lado, centralizados."}],"resources":[{"label":"VS Code para Web (editor no navegador)","url":"https://vscode.dev/","note":"Gratuito, sem instalar","kind":"link"},{"label":"MDN Web Docs em português","url":"https://developer.mozilla.org/pt-BR/","note":"Documentação oficial de HTML/CSS/JS","kind":"link"}],"challenge":{"x":"Identidade visual. Amanhã: dar VIDA à página com JavaScript e criar o mini-jogo!","steps":["Defina uma paleta de 2 ou 3 cores e use-a de forma consistente.","Deixe o botão com um efeito de hover (button:hover { ... }).","Garanta bom espaçamento (nada 'grudado')."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Selector","pt":"O que o CSS mira","phon":"se-LÉK-tor","desc":"O que o CSS mira (ex.: body, button, .classe)."},{"en":"Class","pt":"Um 'apelido'","phon":"CLÁS","desc":"Um 'apelido' (.container) para estilizar vários elementos."},{"en":"Property","pt":"O que muda","phon":"PRÓ-per-ti","desc":"O que muda (color, font-size, margin...)."},{"en":"Color","pt":"Cor","phon":"CÂ-lor","desc":"Cor (ex.: #0EA5A9)."},{"en":"Margin","pt":"Espaço POR FORA do elemento","phon":"MÁR-jin","desc":"Espaço POR FORA do elemento."},{"en":"Flexbox","pt":"Sistema para alinhar…","phon":"FLÉKS-boks","desc":"Sistema para alinhar elementos em linha/coluna."}],"pairs":[["Selector","O que o CSS mira"],["Class","Um 'apelido'"],["Property","O que muda"],["Color","Cor"],["Margin","Espaço POR FORA do elemento"],["Flexbox","Sistema para alinhar…"]]}}$bweb2$::jsonb);
