ocê jogou:\", escolha);","  }","</script>"],"cap":"onclick chama a função ao clicar. console.log mostra a mensagem no Console (F12)."},{"t":"h","x":"O jogo: Pedra, Papel e Tesoura"},{"t":"code","lang":"JavaScript","lines":["function jogar(escolha) {","  const op = [\"pedra\", \"papel\", \"tesoura\"];","  const pc = op[Math.floor(Math.random() * 3)];","  let r;","  if (escolha === pc) r = \"Empate!\";","  else if (","    (escolha===\"pedra\"   && pc===\"tesoura\") ||","    (escolha===\"papel\"   && pc===\"pedra\")   ||","    (escolha===\"tesoura\" && pc===\"papel\")","  ) r = \"Você venceu!\";","  else r = \"Você perdeu...\";","  document.getElementById(\"res\").textContent = \"PC: \"+pc+\" - \"+r;","}"],"cap":"Math.random sorteia o PC; o if/else aplica as regras; o resultado aparece no <p id='res'>."},{"t":"h","x":"Trocar o tema (claro/escuro)"},{"t":"code","lang":"HTML + JavaScript","lines":["<button onclick=\"document.body.classList.toggle('claro')\">","  Trocar tema","</button>","","<!-- no CSS: -->",".claro { background: #f8fafc; color: #0f172a; }"],"cap":"classList.toggle liga/desliga a classe 'claro' no body, alternando o tema num clique."}],"resources":[{"label":"VS Code para Web (editor no navegador)","url":"https://vscode.dev/","note":"Gratuito, sem instalar","kind":"link"},{"label":"MDN Web Docs em português","url":"https://developer.mozilla.org/pt-BR/","note":"Documentação oficial de HTML/CSS/JS","kind":"link"}],"challenge":{"x":"Deixe o jogo seu. Amanhã: caçar bugs no Console, deixar responsiva e apresentar!","steps":["Adicione um placar (variável) que conta suas vitórias.","Mude as mensagens de resultado para o seu estilo.","Garanta que o botão de tema funciona nos dois sentidos."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Variable","pt":"Uma 'caixinha' que guarda um…","phon":"VÉ-ri-a-bol","desc":"Uma 'caixinha' que guarda um valor (let/const)."},{"en":"Function","pt":"Um bloco de código que…","phon":"FÂNK-shon","desc":"Um bloco de código que executa uma tarefa."},{"en":"Event","pt":"Algo que acontece","phon":"i-VÊNT","desc":"Algo que acontece (ex.: um clique)."},{"en":"Click","pt":"O evento de clicar","phon":"CLIK","desc":"O evento de clicar (onclick)."},{"en":"Console","pt":"Painel do navegador onde…","phon":"con-SÓL","desc":"Painel do navegador onde vemos erros (F12)."},{"en":"Random","pt":"Aleatório","phon":"RÉN-dom","desc":"Aleatório (Math.random gera sorteio)."}],"pairs":[["Variable","Uma 'caixinha' que guarda um…"],["Function","Um bloco de código que…"],["Event","Algo que acontece"],["Click","O evento de clicar"],["Console","Painel do navegador onde…"],["Random","Aleatório"]]}}$bweb3$::jsonb);
