  if n >= 4 then
    update public.lessons
       set title = $tweb4$Testar, publicar e apresentar$tweb4$, description = $dweb4$Depurar com o Console, deixar a página responsiva, publicar (opcional) e apresentar no navegador.$dweb4$, body = $bweb4${"intro":"Depurar com o Console, deixar a página responsiva, publicar (opcional) e apresentar no navegador.","material":[{"t":"h","x":"Debug: ler o erro é meio caminho"},{"t":"p","x":"Bug é qualquer comportamento errado. O Console (F12) mostra a mensagem e a LINHA do problema. Aprender a ler esse recado é uma das habilidades mais valiosas de quem programa."},{"t":"h","x":"Publicar na internet"},{"t":"p","x":"Você pode colocar a página no ar: arraste a pasta no Netlify Drop ou use o GitHub Pages. Aí é só compartilhar o link com quem quiser — sua página no mundo real!"},{"t":"h","x":"Passo a passo"},{"t":"h","x":"Cace bugs no Console"},{"t":"p","x":"Abra o navegador, aperte F12 e veja o Console. Corrija cada erro (nome, id, aspas, chaves)."},{"t":"img","url":"assets/web/onde_clicar_aula4.png","cap":"Onde clicar — diagrama do material oficial do curso."},{"t":"h","x":"Deixe responsiva"},{"t":"p","x":"No <head>, adicione a meta viewport e use tamanhos flexíveis (%, flex) para funcionar no celular (slide)."},{"t":"h","x":"Polir"},{"t":"p","x":"Revise cores, espaçamentos e textos. Confira se o jogo e o tema funcionam sempre."},{"t":"h","x":"Publicar (opcional)"},{"t":"p","x":"Arraste a pasta em app.netlify.com/drop OU use GitHub Pages. Você recebe um link público para compartilhar."},{"t":"h","x":"Apresente"},{"t":"p","x":"Abra a página na TV, jogue o mini-jogo e mostre 1 trecho de HTML, 1 de CSS e 1 de JS que você criou."},{"t":"h","x":"Código da aula"},{"t":"h","x":"Tornar responsivo"},{"t":"code","lang":"HTML + CSS","lines":["<!-- dentro do <head> -->","<meta name=\"viewport\"","      content=\"width=device-width, initial-scale=1\">","","/* no CSS: largura flexível */","img { max-width: 100%; height: auto; }"],"cap":"A meta viewport faz o navegador respeitar o tamanho da tela; max-width:100% evita imagens estourando."}],"resources":[{"label":"VS Code para Web (editor no navegador)","url":"https://vscode.dev/","note":"Gratuito, sem instalar","kind":"link"},{"label":"MDN Web Docs em português","url":"https://developer.mozilla.org/pt-BR/","note":"Documentação oficial de HTML/CSS/JS","kind":"link"}],"challenge":{"x":"No ar! Parabéns! Você é oficialmente um(a) criador(a) da web.","steps":["Zero erros no Console (F12).","Página legível no computador E no celular.","Mini-jogo e tema funcionando; apresentada (e, se quiser, publicada)."]},"english":{"intro":"Ligue cada palavra em inglês à tradução.","terms":[{"en":"Bug","pt":"Um erro no código","phon":"BÂG","desc":"Um erro no código."},{"en":"Debug","pt":"Encontrar e corrigir o erro","phon":"di-BÂG","desc":"Encontrar e corrigir o erro."},{"en":"Browser","pt":"Navegador","phon":"BRÁU-zer","desc":"Navegador (Chrome, Edge, Firefox)."},{"en":"Responsive","pt":"Que se adapta a telas de…","phon":"res-PÓN-siv","desc":"Que se adapta a telas de tamanhos diferentes."},{"en":"Console","pt":"Painel de erros","phon":"con-SÓL","desc":"Painel de erros/mensagens (F12)."},{"en":"Deploy","pt":"Publicar o site na internet","phon":"di-PLÓI","desc":"Publicar o site na internet."}],"pairs":[["Bug","Um erro no código"],["Debug","Encontrar e corrigir o erro"],["Browser","Navegador"],["Responsive","Que se adapta a telas de…"],["Console","Painel de erros"],["Deploy","Publicar o site na internet"]]}}$bweb4$::jsonb
